from dataclasses import dataclass, field
from enum import Enum
from datetime import date
from typing import Optional

class RAGStatus(Enum):
    GREEN   = "green"
    AMBER   = "amber"
    RED     = "red"
    BLOCKED = "blocked"

@dataclass
class MilestoneStatus:
    name: str
    target_date: date
    forecast_date: date
    rag: RAGStatus
    owner: str

    @property
    def slip_days(self) -> int:
        return max(0, (self.forecast_date - self.target_date).days)

    def label(self) -> str:
        if self.rag == RAGStatus.GREEN:
            return "ON TRACK"
        if self.rag == RAGStatus.BLOCKED:
            return "BLOCKED"
        return f"AT RISK +{self.slip_days}d" if self.slip_days else "AT RISK"

@dataclass
class RiskItem:
    description: str
    rag: RAGStatus
    owner: str
    mitigation: str = ""

@dataclass
class DecisionRequest:
    description: str
    deadline: date
    approver: str
    consequence_if_delayed: str

@dataclass
class WeeklyStatusReport:
    programme: str
    reporting_week: int          # ISO week number
    report_date: date
    overall_rag: RAGStatus
    owner: str
    highlights: list[str]        # max 5 bullet points
    risks: list[RiskItem]        # max 5 items, highest risk first
    milestones: list[MilestoneStatus]
    next_week_commitments: list[str]   # specific, owner-tagged, date-tagged
    decisions_needed: list[DecisionRequest]

    def validate(self) -> list[str]:
        errors = []
        if len(self.highlights) > 5:
            errors.append(f"Too many highlights: {len(self.highlights)} (max 5)")
        if len(self.risks) > 5:
            errors.append(f"Too many risk items: {len(self.risks)} (max 5)")
        if len(self.next_week_commitments) > 5:
            errors.append("Too many commitments (max 5)")
        if not self.decisions_needed and self.overall_rag in (RAGStatus.AMBER, RAGStatus.RED):
            errors.append("AMBER/RED overall RAG requires at least one DecisionRequest")
        return errors

    def overall_rag_label(self) -> str:
        return self.overall_rag.value.upper()

from enum import Enum

class ReportAudience(Enum):
    TEAM        = "team"         # engineering leads; full detail
    PROGRAMME   = "programme"    # PM and delivery director; standard 5-section
    EXECUTIVE   = "executive"    # sponsors and steering; one-page, financials
    PORTFOLIO   = "portfolio"    # PMO roll-up; RAG only + key dates

def render_report(report: WeeklyStatusReport, audience: ReportAudience) -> dict:
    base = {
        "programme": report.programme,
        "week": report.reporting_week,
        "overall_rag": report.overall_rag_label(),
    }
    if audience == ReportAudience.EXECUTIVE:
        # Sponsors see only the top risk and the next milestone
        next_ms = next(
            (m for m in report.milestones if m.rag != RAGStatus.GREEN),
            report.milestones[0] if report.milestones else None,
        )
        top_risk = report.risks[0] if report.risks else None
        return {
            **base,
            "top_risk": top_risk.description if top_risk else "None",
            "next_milestone": next_ms.name if next_ms else "None",
            "next_milestone_status": next_ms.label() if next_ms else "N/A",
            "decisions_needed": len(report.decisions_needed),
        }
    if audience == ReportAudience.PORTFOLIO:
        # PMO roll-up: just RAG and milestone dates
        return {
            **base,
            "milestones": [
                {"name": m.name, "target": str(m.target_date), "rag": m.rag.value}
                for m in report.milestones
            ],
        }
    # Default: return all sections
    return {
        **base,
        "highlights": report.highlights,
        "risks": [{"desc": r.description, "rag": r.rag.value, "owner": r.owner}
                  for r in report.risks],
        "milestones": [{"name": m.name, "status": m.label()} for m in report.milestones],
        "commitments": report.next_week_commitments,
        "decisions": [{"desc": d.description, "deadline": str(d.deadline)}
                      for d in report.decisions_needed],
    }

import json, urllib.request

def post_status_summary_to_slack(
    report: WeeklyStatusReport,
    webhook_url: str,
) -> None:
    """Post a concise status summary to a Slack channel via incoming webhook."""
    rag_emoji = {"green": ":large_green_circle:", "amber": ":large_yellow_circle:",
                 "red": ":red_circle:", "blocked": ":no_entry:"}
    emoji = rag_emoji.get(report.overall_rag.value, ":white_circle:")

    blocks = [
        {
            "type": "header",
            "text": {"type": "plain_text",
                     "text": f"{emoji} W{report.reporting_week} Status: {report.programme}"},
        },
        {
            "type": "section",
            "fields": [
                {"type": "mrkdwn", "text": f"*Overall RAG:* {report.overall_rag_label()}"},
                {"type": "mrkdwn", "text": f"*Owner:* {report.owner}"},
            ],
        },
    ]
    if report.decisions_needed:
        decisions_text = "\n".join(
            f"• {d.description} (due {d.deadline}, {d.approver})"
            for d in report.decisions_needed
        )
        blocks.append({
            "type": "section",
            "text": {"type": "mrkdwn",
                     "text": f"*Decisions needed:*\n{decisions_text}"},
        })

    payload = json.dumps({"blocks": blocks}).encode()
    req = urllib.request.Request(
        webhook_url, data=payload,
        headers={"Content-Type": "application/json"}, method="POST"
    )
    with urllib.request.urlopen(req, timeout=10) as resp:
        if resp.status != 200:
            raise RuntimeError(f"Slack webhook returned {resp.status}")
